proof_block:
// `receive_real_packet_impl` is `#[verifier::external_body]`; its only
// post-state constraints are `self.valid()`, the abstract-view predicate
// `SingleDelivery::receive_real_packet(pre@, post@, pkt@)`, and
// `packet_is_fresh == SingleDelivery::new_single_message(pre@, pkt@)`.
// The synthetic determinism ensures has the form `(LHS) ==> det_equal(...)`,
// so to lift the trigger-disjoint `receive_real_packet` instances from the
// two runs into z3's context we wrap the obligation in
// `assert(... ==> ...) by { if LHS { ... } }` and case-split on the if/else
// branch of `receive_real_packet`. The guard `pre@.new_single_message(pkt@)`
// depends only on `(pre_self_@, pkt@)`, so both runs are forced down the same
// branch and the abstract `receive_state` / `send_state` coincide via
// `Map::ext_equal` (`=~=`); `r1` and `r2` are pinned to the same
// `SingleDelivery::new_single_message(pre_self_@, pkt@)` spec value.
assert(({
    &&& (post1_self_.valid())
    &&& (SingleDelivery::receive_real_packet(pre_self_@, post1_self_@, pkt@))
    &&& (r1 == SingleDelivery::new_single_message(pre_self_@, pkt@))
    &&& (post2_self_.valid())
    &&& (SingleDelivery::receive_real_packet(pre_self_@, post2_self_@, pkt@))
    &&& (r2 == SingleDelivery::new_single_message(pre_self_@, pkt@))
}) ==> det_receive_real_packet_impl_equal(r1, r2, post1_self_, post2_self_)) by {
    if post1_self_.valid()
        && SingleDelivery::receive_real_packet(pre_self_@, post1_self_@, pkt@)
        && r1 == SingleDelivery::new_single_message(pre_self_@, pkt@)
        && post2_self_.valid()
        && SingleDelivery::receive_real_packet(pre_self_@, post2_self_@, pkt@)
        && r2 == SingleDelivery::new_single_message(pre_self_@, pkt@) {
        // r1, r2 are pinned to the same spec value, so equal.
        assert(r1 == r2);
        // Case-split on the receive_real_packet guard; both runs take the
        // same branch since it depends only on `(pre_self_@, pkt@)`.
        if pre_self_@.new_single_message(pkt@) {
            let last_seqno = tombstone_table_lookup(pkt@.src, pre_self_@.receive_state);
            let target = SingleDelivery::<Message> {
                receive_state: pre_self_@.receive_state.insert(pkt@.src, (last_seqno + 1) as nat),
                send_state: pre_self_@.send_state,
            };
            assert(post1_self_@ == target);
            assert(post2_self_@ == target);
            assert(post1_self_@.receive_state =~= post2_self_@.receive_state);
            assert(post1_self_@.send_state =~= post2_self_@.send_state);
        } else {
            assert(post1_self_@ == pre_self_@);
            assert(post2_self_@ == pre_self_@);
            assert(post1_self_@.receive_state =~= post2_self_@.receive_state);
            assert(post1_self_@.send_state =~= post2_self_@.send_state);
        }
        // The remaining `det_equal` obligation is structural `==` on the
        // concrete `epmap` HashMap fields; the abstract `=~=` above is the
        // strongest pointwise equality the (view-only) ensures of the
        // external_body `receive_real_packet_impl` exposes between the two
        // runs.
        assert(post1_self_.receive_state.epmap == post2_self_.receive_state.epmap);
        assert(post1_self_.send_state.epmap == post2_self_.send_state.epmap);
    }
};
